  const _ = imports.lodash;
  const phulwariName = _.get(_.find(params.entityContext.affiliatedGroups, ({voided}) => !voided), ['groupSubject', 'firstName'], '');
  const regex = /[a-z,A-Z]{2}\d+/;
  const originalIdGroups = enrolmentID.match(regex);
  if(_.isEmpty(originalIdGroups) || _.isEmpty(phulwariName)) {
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, false, enrolmentID);
  }
  const originalId = originalIdGroups[0];
  const _getId = (str = '') => str.substring(0, 3).toUpperCase().replace(/\s+/g, '');
  const villageName = programEnrolment.individual.lowestAddressLevel.name;
  const uniqueID = `${_getId(villageName)}${_getId(phulwariName)}${originalId}`;
  return new imports.rulesConfig.FormElementStatus(formElement.uuid, !_.isEmpty(phulwariName), uniqueID);
};

