"use strict";
({ params, imports }) => {
    const encounter = params.entity;
    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        encounter
    });
    const visitDate = encounter.earliestVisitDateTime || encounter.encounterDateTime;
    let earliestVisitDate = imports.moment(visitDate).add(1, 'days').toDate();
    let weekDayName =  imports.moment(earliestVisitDate).format('ddd');

    if(_.isEqual(weekDayName,'Sun')){
        earliestVisitDate = imports.moment(visitDate).add(2, 'days').toDate();
        weekDayName =  imports.moment(earliestVisitDate).format('ddd');
    }

    scheduleBuilder.add({
            name: "Daily Attendance" +' -'+weekDayName,
            encounterType: "Daily Attendance Form",
            earliestDate: earliestVisitDate,
            maxDate: earliestVisitDate
        }
    );

    const groupSubject = params.entity.individual.groupSubjects;
    const children = [];
    const childrenDetails = [];

 groupSubject.forEach((groupSubject) => {
         if (!groupSubject.memberSubject.voided) {
            children.push(groupSubject.memberSubject.uuid);
            childrenDetails.push(groupSubject.memberSubject);
            }
        });

    let currentVisitAttendance = encounter.getObservationReadableValue('Children present in phulwari');

    const encounters = encounter.individual.getEncounters(true);


    let enc1 = _.chain(encounters)
        .filter((enc) => enc.encounterDateTime)
        .filter((enc) => enc.encounterDateTime < encounter.encounterDateTime)
        .nth(0)
        .value();

    let enc2 = _.chain(encounters)
        .filter((enc) => enc.encounterDateTime)
        .filter((enc) => enc.encounterDateTime < encounter.encounterDateTime)
        .filter((enc) => !_.isNil(enc.encounterDateTime))
        .nth(1)
        .value();

    let enc1VisitAttendance = -1, enc2VisitAttendance = -1;

    if (enc1 && enc2) {
        enc1VisitAttendance = enc1.getObservationReadableValue('Children present in phulwari');
        let enc1VisitAbsentChildern = _.difference(children, enc1VisitAttendance);

        enc2VisitAttendance = enc2.getObservationReadableValue('Children present in phulwari');
        let enc2VisitAbsentChildern = _.difference(children, enc2VisitAttendance);

        let currentVisitAbsentChildern = _.difference(children, currentVisitAttendance);

        let lastThreeVisitAbsentChildren = _.chain(currentVisitAbsentChildern)
            .filter(e => _.includes(enc1VisitAbsentChildern,e)  === true)
            .filter(e => _.includes(enc2VisitAbsentChildern,e)  === true)
            .value();

        //console.log('lastThreeVisitAbsentChildren',lastThreeVisitAbsentChildren);

        if(lastThreeVisitAbsentChildren)
            lastThreeVisitAbsentChildren.forEach((e) => {


                let subject = _.chain(childrenDetails)
                    .filter(childrenDetail => _.isEqual(childrenDetail.uuid,e)  === true)
                    .value();

                let hasAbsentResumeDate = subject[0].findLatestObservationFromEncounters('Date of phulwari resume',encounter);
                let resumeDate;
                if(hasAbsentResumeDate){
                    resumeDate = hasAbsentResumeDate.getReadableValue();
                }

                if(resumeDate != undefined){
                    if(imports.moment(visitDate).isAfter(resumeDate,'date'))
                        scheduleBuilder.add({
                            name: "Child Absent followup Form",
                            encounterType: "Child Absent followup Form",
                            earliestDate: imports.moment(visitDate).toDate(),
                            maxDate: imports.moment(visitDate).add(2, 'days').toDate(),
                            subjectUUID: e
                        });
                }else
                    scheduleBuilder.add({
                        name: "Child Absent followup Form",
                        encounterType: "Child Absent followup Form",
                        earliestDate: imports.moment(visitDate).toDate(),
                        maxDate: imports.moment(visitDate).add(2, 'days').toDate(),
                        subjectUUID: e
                    });
            });

    }




    return scheduleBuilder.getAll();
};

