"use strict";
({params, imports}) => {
    const programEncounter = params.entity;
    const moment = imports.moment;
    const FEB = 1;
    const AUG = 7;
    const findSlot = (anyDate) => {
        anyDate = moment(anyDate).startOf('day').toDate();
        if (moment(anyDate).month() < FEB) {
            return moment(anyDate).startOf('month').month(FEB).toDate();
        }
        if (moment(anyDate).month() === FEB) {
            return anyDate;
        }
        if (moment(anyDate).month() < AUG) {
            return moment(anyDate).startOf('month').month(AUG).toDate();
        }
        if (moment(anyDate).month() === AUG) {
            return anyDate;
        }
        return moment(anyDate).add(1, 'year').month(FEB).startOf('month').toDate();
    };

    const getVisitSchedule = (_earliestDate) => {
        let earliestDate = moment(_earliestDate).startOf('day').toDate();
        let maxDate = moment(earliestDate).endOf('month').toDate();
        if (moment(_earliestDate).month() === FEB) {
            return {
                name: 'Albendazole FEB',
                encounterType: 'Albendazole',
                earliestDate,
                maxDate,
            }
        }
        return {
            name: 'Albendazole AUG',
            encounterType: 'Albendazole',
            earliestDate,
            maxDate,
        }
    };

    const findNextSlot = (currentVisitScheduledDate) => {
        let guessedDate = moment(currentVisitScheduledDate).startOf('month').add(1, 'months').startOf('day').toDate();
        return findSlot(guessedDate);
    };

    const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({
        programEncounter,
        programEnrolment: programEncounter.programEnrolment
    });
    const visitSchedule = getVisitSchedule(findNextSlot(programEncounter.earliestVisitDateTime));
    if (moment().isSameOrBefore(visitSchedule.maxDate, 'day')) {
        scheduleBuilder.add(visitSchedule);
    }
    return scheduleBuilder.getAllUnique("encounterType");
};

"use strict";
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const _ = imports.lodash;
  const myGroups = programEncounter.programEnrolment.individual.groups;

  // ✅ If earliestVisitDateTime is missing (like after cancel), 
  // use the last valid scheduled or encounter date.
  let scheduledDateTime = programEncounter.earliestVisitDateTime;

  if (_.isNil(scheduledDateTime)) {
    // fallback: use encounterDateTime or enrolmentDateTime as base
    scheduledDateTime =
      programEncounter.encounterDateTime ||
      programEncounter.programEnrolment.enrolmentDateTime;

    if (_.isNil(scheduledDateTime)) {
      // still nothing? then safely exit
      return [];
    }
  }

  const groupSubject = _.get(
    _.find(myGroups, (g) => !g.voided && g.groupSubject.subjectType.name === "Phulwari"),
    "groupSubject"
  );

  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ programEncounter });

  if (!_.isNil(groupSubject)) {
    const dayOfMonth = groupSubject.getObservationReadableValue(
      "Day of month for growth monitoring visit"
    );

    // Calculate next month for visit (wrap December → January)
    const monthForNextVisit =
      moment(scheduledDateTime).month() !== 11
        ? moment(scheduledDateTime).month() + 1
        : 0;

    let earliestDate = moment(scheduledDateTime)
      .month(monthForNextVisit)
      .date(dayOfMonth)
      .toDate();

    // ✅ Handle month-end cases (e.g. day doesn’t exist)
    if (moment(earliestDate).month() !== monthForNextVisit) {
      earliestDate = moment(scheduledDateTime).add(1, "M").endOf("month").toDate();
    } else {
      earliestDate = moment(scheduledDateTime).add(1, "M").date(dayOfMonth).toDate();
    }

    const maxDate = moment(earliestDate).add(3, "days").toDate();

    scheduleBuilder.add({
      name: "Growth Monitoring Visit",
      encounterType: "Anthropometry Assessment",
      earliestDate,
      maxDate,
    });
  }

  return scheduleBuilder.getAll();
};

